export function getMaasehNisimZman(month: number, day: number): MaasehNisimRow | undefined {
  const key = `${String(month).padStart(2, '0')}/${String(day).padStart(2, '0')}`;
  return MAASEH_NISIM_TABLE.get(key);
}

/**
 * Converts a minutes-from-midnight value to a Date in the given timezone.
 * The table values are in **local clock time** (IST or IDT depending on season).
 * We determine the actual UTC offset for the reference date and use that.
 */
export function mnMinutesToDate(
  minutesFromMidnight: number,
  referenceDate: Date,
  timezone: string,
): Date {
  const hours = Math.floor(minutesFromMidnight / 60);
  const minutes = minutesFromMidnight % 60;

  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  });

  const refParts = formatter.formatToParts(referenceDate);
  const getPart = (type: string) => refParts.find(p => p.type === type)?.value ?? '';
  const refYear = parseInt(getPart('year'), 10);
  const refMonth = parseInt(getPart('month'), 10) - 1;
  const refDay = parseInt(getPart('day'), 10);

  // Build a noon UTC Date for the reference day to determine the local offset
  const noonUtc = Date.UTC(refYear, refMonth, refDay, 12, 0, 0, 0);
  const noonDate = new Date(noonUtc);
  const noonParts = formatter.formatToParts(noonDate);
  const localHour = parseInt(noonParts.find(p => p.type === 'hour')?.value ?? '12', 10);
  // offset = localHour - 12 (UTC hour) in hours; convert to minutes
  const offsetMinutes = (localHour - 12) * 60;

  const utcMs = Date.UTC(refYear, refMonth, refDay, hours, minutes, 0, 0) - offsetMinutes * 60_000;

  return new Date(utcMs);
}
